import React, { useState } from "react";
import './Logout.css';
import './Welcome';
import { useNavigate } from "react-router";
import axios from "axios";
function Logout () {
    const [data, setData] = useState([]); 
    const navigate = useNavigate();
    const GetCall = (props) => {
        axios.get(`http://localhost:8080/user/${props.userName}/items`).then(response => setData(response.data.id))
    }
    return <div className="nav-bar">
    <div className="header">
    <a href="#default" className="logo">Productiv</a>
    <div className="header-right">
    <a href="#home">My Account</a>
    <a href="#contact" onClick={() => navigate('/')} >Logout</a>
  </div>
    </div>
        <h1> Welcome!</h1>
        <GetCall userName= 'userName'></GetCall>
    </div>
}

export default Logout;
